:root {
  --ink: #071018;
  --ink-soft: #16090a;
  --surface: #0b141f;
  --surface-rail: #0d1823;
  --surface-panel: #111d2b;
  --blood: #ff4655;
  --amber: #f6b35b;
  --warn: #ffd166;
  --cyan: #7cf7ff;
  --friendly: #59ff9f;
  --bone: #f8fbff;
  --ash: #96a7b8;
  --line: rgba(248,251,255,.14);
  --line-strong: rgba(248,251,255,.28);
  --glow-red: rgba(255,70,85,.28);
  --bg: var(--ink);
  --fg: var(--bone);
  --muted: var(--ash);
  --primary: var(--blood);
  --accent: var(--amber);
  --success: var(--friendly);
  --border: var(--line);
  --border-strong: var(--line-strong);
  --hud-h: 64px;
  --rail-h: 44px;
  --radius: 2px;
  --radius-lg: 4px;
  --shadow: 0 16px 48px rgba(0,0,0,.45);
  --mono: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;
  --sans: "Inter", "PingFang SC", "Microsoft YaHei", system-ui, sans-serif;
  --ease: cubic-bezier(.2,.8,.2,1);
}
*,*::before,*::after{box-sizing:border-box}
html,body{margin:0;padding:0;background:var(--bg);color:var(--fg);font-family:var(--sans);font-size:.96rem;line-height:1.55;overflow-x:hidden}
body{min-height:100vh}
a{color:inherit;text-decoration:none}
button{font-family:inherit;cursor:pointer;border:none;background:none;color:inherit}
a,button{min-height:44px;display:inline-flex;align-items:center;gap:.5rem}
:where(a,button):focus-visible{outline:2px solid var(--warn);outline-offset:3px}
img{max-width:100%;display:block}
#root{min-height:100vh;position:relative}
.app-shell{position:relative;background:radial-gradient(circle at 20% 0%, rgba(255,70,85,.08), transparent 30%), radial-gradient(circle at 85% 10%, rgba(124,247,255,.06), transparent 28%), var(--bg)}
.scanlines{pointer-events:none;position:fixed;inset:0;background:repeating-linear-gradient(transparent 0, transparent 3px, rgba(255,255,255,.025) 3px, rgba(255,255,255,.025) 4px);z-index:60;mix-blend-mode:overlay;opacity:.45}
.hud-nav{position:fixed;top:0;left:0;right:0;height:var(--hud-h);z-index:50;display:grid;grid-template-columns:1fr auto 1fr;align-items:center;padding:0 clamp(1rem,3vw,2rem);gap:1rem;background:linear-gradient(180deg, rgba(7,16,24,.96), rgba(7,16,24,.7) 70%, transparent);border-bottom:1px solid var(--border);backdrop-filter:blur(6px)}
.brand{display:flex;align-items:center;gap:.85rem;font-family:var(--mono);font-weight:700;letter-spacing:.18em;text-transform:uppercase}
.brand-mark{width:30px;height:30px;display:grid;place-items:center;background:var(--primary);color:var(--ink-soft);clip-path:polygon(0 0, 100% 0, 82% 100%, 0 100%);font-weight:900;font-size:.9rem}
.brand-name{font-size:.86rem}
.brand-name span{color:var(--primary)}
.nav-links{display:flex;gap:.25rem;justify-content:center;flex-wrap:wrap}
.nav-link{font-family:var(--mono);font-size:.72rem;letter-spacing:.18em;text-transform:uppercase;color:var(--muted);padding:0 1rem;border-inline:1px solid transparent;position:relative}
.nav-link:hover{color:var(--fg)}
.nav-link.active{color:var(--accent)}
.nav-link.active::after{content:"";position:absolute;left:.8rem;right:.8rem;bottom:.35rem;height:2px;background:var(--accent)}
.hud-status{display:flex;align-items:center;gap:.75rem;justify-content:flex-end;font-family:var(--mono);font-size:.7rem;letter-spacing:.12em;text-transform:uppercase;color:var(--muted)}
.status-pip{width:8px;height:8px;border-radius:50%;background:var(--success);box-shadow:0 0 0 3px rgba(89,255,159,.18);animation:pulse 2s var(--ease) infinite}
@keyframes pulse{50%{box-shadow:0 0 0 6px rgba(89,255,159,0)}}

