import { useState } from "react";
import { missionBrief, navItems, squad, armory, maps, timeline, feedLines, stats } from "./content.js";
import "./App.css";

function HudChip({ tone = "hot", label }: { tone?: string; label: string }) {
  return <span className={`hud-chip chip-${tone}`}><span className="pip" />{label}</span>;
}
function SiteChip({ letter, tone }: { letter: string; tone: string }) {
  return <span className={`site-chip site-${tone}`}><span className="site-letter">{letter}</span><span className="site-label">SITE</span></span>;
}
function Bar({ value, tone = "blood" }: { value: number; tone?: string }) {
  return <div className="bar-track"><div className={`bar-fill bar-${tone}`} style={{ width: `${value}%` }} /></div>;
}

export function App() {
  const [activeNav, setActiveNav] = useState("brief");
  const [selectedOp, setSelectedOp] = useState(0);
  const [selectedMap, setSelectedMap] = useState(0);
  const op = squad[selectedOp];
  const map = maps[selectedMap];
  return (
    <div className="app-shell scanlines">
      <nav className="hud-nav" aria-label="主导航">
        <div className="brand"><span className="brand-mark">T</span><span className="brand-name">TACTICAL//OPS</span></div>
        <div className="nav-links">{navItems.map(n => <a key={n.id} href={`#${n.id}`} className={`nav-link ${activeNav === n.id ? "active" : ""}`} onClick={() => setActiveNav(n.id)}>{n.label}</a>)}</div>
        <div className="hud-status"><span className="status-pip hot" /><span>在线 {missionBrief.online.toLocaleString()}</span><span className="status-meta">{missionBrief.tickrate}</span></div>
      </nav>
      <main>
        <section className="hero-stage" id="brief">
          <div className="hero-bg" style={{ backgroundImage: "url(/assets/tactical-bg.jpg)" }} />
          <div className="hero-grid" />
          <div className="hero-overlay">
            <div className="hero-side">
              <div className="hero-kicker">MISSION BRIEF//{missionBrief.codename}</div>
              <HudChip tone="amber" label={missionBrief.status} />
            </div>
            <div className="hero-core">
              <h1>{missionBrief.codename}</h1>
              <p className="hero-objective">{missionBrief.objective}</p>
              <div className="hero-meta">
                <div><span className="meta-label">回合</span><span className="meta-value">{missionBrief.round}</span></div>
                <div><span className="meta-label">比分</span><span className="meta-value">{missionBrief.score}</span></div>
                <div className="timer-block"><span className="meta-label">T-MINUS</span><span className="timer">{missionBrief.timer}</span></div>
              </div>
            </div>
            <div className="hero-radar">
              <div className="radar"><div className="radar-sweep" /><span className="radar-ring" /><span className="radar-dot dot-a" /><span className="radar-dot dot-b" /><span className="radar-dot dot-c" /></div>
              <div className="radar-tags"><span>A 长道</span><span>B 连廊</span><span>C 平台</span></div>
            </div>
          </div>
          <div className="brief-strip">{stats.map(s => <div key={s.label} className="brief-metric"><span>{s.label}</span><strong>{s.value}</strong></div>)}</div>
        </section>
        <section className="squad-rail" id="squad">
          <div className="section-head"><span className="section-index">01//SQUAD</span><h2>干员阵容</h2></div>
          <div className="squad-track" role="tablist">{squad.map((s, i) => <button key={s.callsign} role="tab" aria-selected={selectedOp === i} className={`squad-tab ${selectedOp === i ? "op-active" : ""}`} onClick={() => setSelectedOp(i)}><span className="op-code">{s.callsign.charAt(0)}</span><span className="op-meta"><strong>{s.callsign}</strong><em>{s.role}</em></span></button>)}</div>
          <div className="op-panel">
            <div className="op-ident"><span className="op-big">{op.callsign.charAt(0)}</span><div><h3>{op.callsign}</h3><p>{op.origin} · {op.role}</p></div></div>
